fn main() {
    let score = 85;
    if score >= 90 {
        println!("A");
    } else if score >= 80 {
        println!("B");
    } else if score >= 70 {
        println!("C");
    } else {
        println!("F");
    }
}

fn main() {
    let n = 7;
    let kind = if n % 2 == 0 { "even" } else { "odd" };
    println!("{} is {}", n, kind);
}

fn main() {
    let mut count = 0;
    let result = loop {
        count += 1;
        if count == 5 {
            break count * 2;
        }
    };
    println!("result: {}", result);
}

fn main() {
    let mut n = 1;
    while n <= 5 {
        print!("{} ", n);
        n += 1;
    }
    println!();
}

fn main() {
    for i in 1..=5 {
        println!("{}", i);
    }
}

fn main() {
    let langs = ["Go", "Rust", "Python"];
    for lang in &langs {
        println!("{}", lang);
    }
}

fn main() {
    for i in 1..=10 {
        if i % 2 == 0 { continue; }
        print!("{} ", i);
    }
    println!();
}
